#!/usr/bin/env python3
"""
validate-lm-head-router.py — GKQ-as-router hypothesis validator.

Tests whether a rank-K SVD reconstruction of the lm_head weight matrix preserves
the *argmax ordering* of the dense logits, even though the per-logit numerical
accuracy is destroyed by quantization. If recall@K of the reconstructed top-1
prediction against the dense top-1 is ≥ 95% for reasonable K, then GKQ becomes
the canonical router for sparse-verify lm_head fetches:

    1. resident: rank-R GKQ sketch of lm_head (~MB)
    2. per-step: matmul against sketch → top-K' candidate tokens
    3. fetch:    K' rows of dense lm_head over wire, recompute exact logits
    4. argmax over K' candidates → final token

This script:
  - loads Qwen2.5-0.5B-Instruct
  - extracts lm_head weight (tied to embed_tokens)
  - for ranks in [3, 32, 64, 128, 256]: SVD-truncate, GKQ-quantize, reconstruct
  - runs 5-10 real prompts through the dense model, collects (hidden, true_top1)
    pairs at every position
  - measures recall@K' for K' in [1, 5, 10, 50, 100]
  - writes a markdown report and (if any rank ≥95% recall@50) a .knot router file
"""

from __future__ import annotations

import os
import sys
import time
from pathlib import Path
from typing import Dict, List, Tuple

import numpy as np
import torch

# Importable helpers from the GKQ v2 toolchain.
sys.path.insert(0, str(Path(__file__).parent))
import gkq_v2_format as gkq  # noqa: E402

# ─────────────────────────────────────────────────────────────────────────────
# CONFIG
# ─────────────────────────────────────────────────────────────────────────────

MODEL_ID = "Qwen/Qwen2.5-0.5B-Instruct"
RANKS = [3, 32, 64, 128, 256]
RECALL_KS = [1, 5, 10, 50, 100]
PROMPTS = [
    "What is the capital of France?",
    "def fibonacci(n):\n    if n < 2:\n        return n\n    return ",
    "Hello, how are you doing today? I was thinking about",
    "The mitochondria is the powerhouse of the",
    "Translate to Spanish: Good morning, my friend. Spanish:",
    "1 + 1 = 2. 2 + 2 = 4. 3 + 3 = ",
    "Once upon a time in a distant kingdom, there lived a",
    "import numpy as np\narr = np.zeros((3, 4))\nprint(arr.",
]

OUTPUT_DIR = Path(__file__).parent
REPORT_PATH = OUTPUT_DIR / "LM_HEAD_ROUTER_REPORT.md"
RKNOTS_DIR = OUTPUT_DIR / "rknots"

ROUTER_RECALL_THRESHOLD = 0.95
ROUTER_K_VERIFY = 50  # K' used when reporting per-step bandwidth


# ─────────────────────────────────────────────────────────────────────────────
# GKQ QUANTIZER (rank-generalized; mirrors _quantize_svd_components in
# quantize-model-weights.py but without the hard pad-to-3 used by the
# legacy attention/FFN path).
# ─────────────────────────────────────────────────────────────────────────────


def quantize_svd_components(U: np.ndarray, sigma: np.ndarray, Vt: np.ndarray):
    """Uint8 max-value quantization, no rank padding."""
    u_max = float(np.abs(U).max() + 1e-10)
    sigma_max = float(np.abs(sigma).max() + 1e-10)
    v_max = float(np.abs(Vt).max() + 1e-10)

    u_q8 = np.clip(np.round((U / u_max) * 255), 0, 255).astype(np.uint8)
    sigma_q8 = np.clip(np.round((sigma / sigma_max) * 255), 0, 255).astype(np.uint8)
    v_q8 = np.clip(np.round((Vt / v_max) * 255), 0, 255).astype(np.uint8)

    return u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max


def dequantize_svd(u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max):
    U = (u_q8.astype(np.float32) / 255.0) * u_max
    sigma = (sigma_q8.astype(np.float32) / 255.0) * sigma_max
    Vt = (v_q8.astype(np.float32) / 255.0) * v_max
    return U, sigma, Vt


def reconstruct_W(U: np.ndarray, sigma: np.ndarray, Vt: np.ndarray) -> np.ndarray:
    return (U * sigma[None, :]) @ Vt


# ─────────────────────────────────────────────────────────────────────────────
# HIDDEN-STATE COLLECTION
# ─────────────────────────────────────────────────────────────────────────────


def collect_hidden_states(model, tokenizer, prompts: List[str]) -> Tuple[np.ndarray, np.ndarray]:
    """Run dense forward passes, gather (hidden, true_top1_token_id) at every position."""
    hidden_list: List[np.ndarray] = []
    true_top1_list: List[int] = []

    with torch.no_grad():
        for prompt in prompts:
            ids = tokenizer(prompt, return_tensors="pt").input_ids
            out = model(ids, output_hidden_states=True, use_cache=False)
            # last hidden state: [1, seq, hidden]
            h = out.hidden_states[-1].squeeze(0).cpu().numpy().astype(np.float32)
            # full dense logits for true top-1 reference: [seq, vocab]
            logits = out.logits.squeeze(0).cpu().numpy().astype(np.float32)
            top1 = logits.argmax(axis=-1)  # [seq]

            hidden_list.append(h)
            true_top1_list.extend(top1.tolist())

    H = np.concatenate(hidden_list, axis=0).astype(np.float32)  # [N, hidden]
    T = np.asarray(true_top1_list, dtype=np.int64)              # [N]
    return H, T


# ─────────────────────────────────────────────────────────────────────────────
# RECALL EVALUATION
# ─────────────────────────────────────────────────────────────────────────────


def eval_router_recall(
    H: np.ndarray, true_top1: np.ndarray, W_approx: np.ndarray, ks: List[int]
) -> Dict[int, float]:
    """Recall@K' = fraction of positions whose dense top-1 is in approx top-K'."""
    # logits_approx: [N, vocab]
    logits_approx = H @ W_approx.T
    max_k = max(ks)
    # argpartition is faster than full argsort for top-K.
    part = np.argpartition(-logits_approx, kth=max_k - 1, axis=-1)[:, :max_k]
    # Sort just the top-max_k columns.
    row_idx = np.arange(part.shape[0])[:, None]
    sorted_top = part[row_idx, np.argsort(-logits_approx[row_idx, part], axis=-1)]

    recalls = {}
    for k in ks:
        topk = sorted_top[:, :k]
        hits = np.any(topk == true_top1[:, None], axis=-1)
        recalls[k] = float(hits.mean())
    return recalls


# ─────────────────────────────────────────────────────────────────────────────
# ROUTER .knot WRITER
# ─────────────────────────────────────────────────────────────────────────────


def write_router_knot(
    path: Path,
    model_id: str,
    rank: int,
    u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max,
    d_out: int, d_in: int,
):
    RKNOTS_DIR.mkdir(exist_ok=True)
    knot_config = {
        "purpose": "lm_head_router",
        "rank": rank,
        "vocab": d_out,
        "hidden": d_in,
        "quantization": "uint8_max_value",
        "note": "GKQ rank-R sketch of tied lm_head. Use for top-K candidate routing; verify with dense rows fetched on demand.",
    }
    with open(path, "wb") as f:
        gkq.write_header(
            f,
            model_name=model_id,
            arch="qwen2",
            knot_config_dict=knot_config,
            num_spectral=1,
            num_dense=0,
        )
        gkq.write_spectral_tensor(
            f,
            name="lm_head.weight",
            u_q8=u_q8,
            sigma_q8=sigma_q8,
            v_q8=v_q8,
            u_max=u_max,
            sigma_max=sigma_max,
            v_max=v_max,
            d_out=d_out,
            d_in=d_in,
            rank=rank,
        )


# ─────────────────────────────────────────────────────────────────────────────
# MAIN
# ─────────────────────────────────────────────────────────────────────────────


def main():
    print(f"[load] {MODEL_ID} (cpu, float32)")
    from transformers import AutoModelForCausalLM, AutoTokenizer

    t0 = time.time()
    tokenizer = AutoTokenizer.from_pretrained(MODEL_ID)
    model = AutoModelForCausalLM.from_pretrained(
        MODEL_ID, torch_dtype=torch.float32, device_map="cpu"
    )
    model.eval()
    print(f"[load] done in {time.time() - t0:.1f}s")

    # In Qwen2.5-0.5B the lm_head is tied to embed_tokens. Either path yields
    # the same weight tensor; the lm_head.weight view is the one used at logit time.
    W = model.lm_head.weight.detach().cpu().numpy().astype(np.float32)  # [vocab, hidden]
    vocab, hidden = W.shape
    print(f"[lm_head] shape={W.shape} dtype=float32  ({W.nbytes / 1024 / 1024:.1f} MB dense)")

    # ── ground-truth hidden states + true top-1 tokens ──────────────────────
    print(f"[hidden] running {len(PROMPTS)} prompts through dense model …")
    t0 = time.time()
    H, true_top1 = collect_hidden_states(model, tokenizer, PROMPTS)
    print(f"[hidden] {H.shape[0]} positions collected in {time.time() - t0:.1f}s")

    # Free the model — we only need W and (H, true_top1) from here on.
    del model
    import gc; gc.collect()

    # ── full SVD once, then truncate per rank ───────────────────────────────
    print(f"[svd] computing full SVD of lm_head [{vocab}×{hidden}] …")
    t0 = time.time()
    U_full, S_full, Vt_full = np.linalg.svd(W, full_matrices=False)
    print(f"[svd] done in {time.time() - t0:.1f}s  (singular range "
          f"{S_full[0]:.3f} … {S_full[-1]:.3e})")

    # ── sweep ranks ─────────────────────────────────────────────────────────
    results: Dict[int, Dict[int, float]] = {}
    quantized_per_rank: Dict[int, Tuple] = {}

    for r in RANKS:
        U_r = U_full[:, :r].copy()
        S_r = S_full[:r].copy()
        Vt_r = Vt_full[:r, :].copy()

        u_q8, s_q8, v_q8, u_max, s_max, v_max = quantize_svd_components(U_r, S_r, Vt_r)
        U_dq, S_dq, Vt_dq = dequantize_svd(u_q8, s_q8, v_q8, u_max, s_max, v_max)
        W_approx = reconstruct_W(U_dq, S_dq, Vt_dq)

        t0 = time.time()
        recalls = eval_router_recall(H, true_top1, W_approx, RECALL_KS)
        dt = time.time() - t0

        results[r] = recalls
        quantized_per_rank[r] = (u_q8, s_q8, v_q8, u_max, s_max, v_max)

        rec_str = "  ".join(f"@{k}={recalls[k]*100:5.2f}%" for k in RECALL_KS)
        print(f"[rank {r:>3}] {rec_str}   (eval {dt:.1f}s)")

    # ── markdown table ──────────────────────────────────────────────────────
    header = "| rank | " + " | ".join(f"recall@{k}" for k in RECALL_KS) + " |"
    sep    = "|---" * (len(RECALL_KS) + 1) + "|"
    rows = []
    for r in RANKS:
        row = f"| {r} | " + " | ".join(f"{results[r][k]*100:.2f}%" for k in RECALL_KS) + " |"
        rows.append(row)
    table = "\n".join([header, sep, *rows])

    # ── bandwidth estimate ──────────────────────────────────────────────────
    # GKQ-router resident: rank × (vocab + hidden) bytes (uint8) + sigma + scalars.
    # ~1 byte/coef. The factor ×1.5 in the spec accounts for max scalars and overhead.
    def router_bytes(r: int) -> int:
        return int(r * (vocab + hidden) * 1.5)

    per_step_bytes = ROUTER_K_VERIFY * hidden * 4  # float32 rows

    # ── verdict ─────────────────────────────────────────────────────────────
    # Choose smallest rank achieving ≥95% recall@K_verify (default 50).
    viable_rank = None
    for r in RANKS:
        if results[r][ROUTER_K_VERIFY] >= ROUTER_RECALL_THRESHOLD:
            viable_rank = r
            break

    if viable_rank is not None:
        verdict = (
            f"ROUTER VIABLE at rank={viable_rank}, K_verify={ROUTER_K_VERIFY} "
            f"(recall={results[viable_rank][ROUTER_K_VERIFY]*100:.2f}%, "
            f"per-step={per_step_bytes / 1024:.1f} KB, "
            f"router-resident≈{router_bytes(viable_rank) / 1024:.1f} KB)"
        )
    else:
        best_rank = max(RANKS, key=lambda r: results[r][ROUTER_K_VERIFY])
        verdict = (
            f"ROUTER NOT VIABLE — recall too low at all tested ranks "
            f"(best: rank={best_rank} recall@{ROUTER_K_VERIFY}="
            f"{results[best_rank][ROUTER_K_VERIFY]*100:.2f}%, "
            f"need ≥{ROUTER_RECALL_THRESHOLD*100:.0f}%)"
        )

    # ── stdout + report ─────────────────────────────────────────────────────
    print()
    print(table)
    print()
    print(verdict)

    report = []
    report.append("# LM-Head GKQ Router Validation\n")
    report.append(f"- model: `{MODEL_ID}`")
    report.append(f"- vocab: {vocab}")
    report.append(f"- hidden: {hidden}")
    report.append(f"- positions evaluated: {H.shape[0]}")
    report.append(f"- prompts: {len(PROMPTS)}")
    report.append(f"- ranks tested: {RANKS}")
    report.append(f"- K_verify for bandwidth budget: {ROUTER_K_VERIFY}\n")
    report.append("## Recall table\n")
    report.append(table)
    report.append("\n## Bandwidth model (option 3 = GKQ-router + sparse verify)\n")
    report.append(f"- per-step fetch: K_verify × hidden × 4 bytes = "
                  f"{ROUTER_K_VERIFY} × {hidden} × 4 = {per_step_bytes / 1024:.1f} KB/step")
    report.append("- router-resident estimate ≈ rank × (vocab + hidden) × 1.5 bytes:")
    for r in RANKS:
        report.append(f"    - rank {r}: ≈ {router_bytes(r) / 1024:.1f} KB")
    report.append("\n## Verdict\n")
    report.append(verdict + "\n")

    REPORT_PATH.write_text("\n".join(report))
    print(f"\n[report] wrote {REPORT_PATH}")

    # ── bonus: write router .knot if viable ────────────────────────────────
    if viable_rank is not None:
        knot_path = RKNOTS_DIR / f"qwen-lm-head-router-rank{viable_rank}.knot"
        q = quantized_per_rank[viable_rank]
        write_router_knot(
            knot_path, MODEL_ID, viable_rank,
            u_q8=q[0], sigma_q8=q[1], v_q8=q[2],
            u_max=q[3], sigma_max=q[4], v_max=q[5],
            d_out=vocab, d_in=hidden,
        )
        size_kb = knot_path.stat().st_size / 1024
        print(f"[router] wrote {knot_path} ({size_kb:.1f} KB)")


if __name__ == "__main__":
    os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
    os.environ.setdefault("OMP_NUM_THREADS", "1")
    main()
